import React, { useEffect, useRef, useState } from 'react';
import { CiBookmarkMinus } from "react-icons/ci";
import { CiSquareCheck } from "react-icons/ci";
import { PiCopySimpleThin } from "react-icons/pi";
import { PiNotePencilThin } from "react-icons/pi";
import { PiTrashThin } from "react-icons/pi";

import './option_in_post.css'

const OptionInPost = ({
    visibleOpcionId,
    itemId,
    showBookmarkSuccess,
    selectedMessageId,
    showCopySuccess,
    isBookmarked,
    bookmarkId,
    currentMessages,
    setEditingMessageId,
    setEditingText,
    setVisibleOpcionId,
    setShowCopySuccess,
    setSelectedMessageId,
    setShowDeleteModal,
    bookmarkedPosts,
    setBookmarkedPosts,
    setShowBookmarkSuccess,
    setShowInput,
    setInputText,
    customBookmarks,
    hideBookmarkIcons = false,
    isInBookmarkModal = false,
    setCustomBookmarkText,
    setShowTextInput,
    onAddToPosts,
    isWithMedia = false
}) => {
    const ref = useRef(null);

    const [tempColor, setTempColor] = useState(null);

    useEffect(() => {
        function handleClickOutside(event) {
            if (ref.current && !ref.current.contains(event.target) && !event.target.closest('.options_post') && !event.target.closest('.option_bookmark')) {
                setVisibleOpcionId(null);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [setVisibleOpcionId]);

    if (visibleOpcionId !== itemId) return null;

    const handleEditClick = (e) => {
        e.stopPropagation();
        const message = currentMessages.find(msg => msg.id === itemId);
        if (message) {
            if (isInBookmarkModal) {
                setCustomBookmarkText(message.text);
                setShowTextInput(true);
                setEditingMessageId(itemId);
            } else {
                setEditingMessageId(itemId);
                setEditingText(message.text);
                // Open the input modal for editing
                setShowInput(true);
                setInputText(message.text + ' ');
            }
        }
        setVisibleOpcionId(null);
    };

    const handleCopyClick = () => {
        const message = currentMessages.find(msg => msg.id === itemId);
        if (message) {
            navigator.clipboard.writeText(message.text);
            setShowCopySuccess(itemId);
            setTimeout(() => {
                setShowCopySuccess(null);
                setVisibleOpcionId(null);
            }, 100);
        }
    };

    const handleDeleteClick = (e) => {
        setTimeout(() => {
            e.stopPropagation();
            setSelectedMessageId(itemId);
            setShowDeleteModal(true);
        }, 0);

    };

    const handleBookmarkPost = () => {
        if (isInBookmarkModal) {
            const bookmarkToAdd = currentMessages.find(msg => msg.id === itemId);
            if (!bookmarkToAdd) return;

            const isAlreadyInPosts = currentMessages.some(msg => msg.bookmarkId === itemId);

            if (!isAlreadyInPosts) {
                if (onAddToPosts) {
                    onAddToPosts(bookmarkToAdd);
                }
                setShowBookmarkSuccess(itemId);
                setTimeout(() => {
                    setShowBookmarkSuccess(null);
                    setVisibleOpcionId(null);
                }, 500);
            }
        } else {
            const messageToBookmark = currentMessages.find(msg => msg.id === itemId);
            if (!messageToBookmark) return;

            const isBookmarked = bookmarkedPosts.some(bookmark => bookmark.id === itemId);

            if (isBookmarked) {
                setBookmarkedPosts(bookmarkedPosts.filter(bookmark => bookmark.id !== itemId));
            } else {
                const newBookmark = {
                    id: messageToBookmark.id,
                    text: messageToBookmark.text,
                    timestamp: messageToBookmark.timestamp,
                    file: messageToBookmark.file
                };
                setBookmarkedPosts([...bookmarkedPosts, newBookmark]);
                setShowBookmarkSuccess(itemId);

                setTimeout(() => {
                    setShowBookmarkSuccess(null);
                    setVisibleOpcionId(null);
                }, 500);
            }
        }
    };

    const handleCustomBookmarkClick = () => {
        if (!isCustomBookmark) return;
        const messageToBookmark = currentMessages.find(msg => msg.id === itemId);
        if (!messageToBookmark) return;

        const alreadyBookmarked = bookmarkedPosts.some(bookmark => bookmark.id === itemId);
        if (!alreadyBookmarked) {
            const newBookmark = {
                id: messageToBookmark.id,
                text: messageToBookmark.text,
                timestamp: messageToBookmark.timestamp,
                file: messageToBookmark.file
            };
            setBookmarkedPosts([...bookmarkedPosts, newBookmark]);
        }

        setTempColor('rgb(255, 145, 0)');
        setTimeout(() => {
            setTempColor(null);
        }, 1000);
    };

    const isCustomBookmark = bookmarkId && customBookmarks && customBookmarks.some(b => b.id === bookmarkId);

    return (
        <div ref={ref} className='opcion' style={isWithMedia ? { top: 'auto', bottom: '2rem', left: '0.5rem', borderRadius: '10px' } : {}} onClick={(e) => e.stopPropagation()}>
            {!hideBookmarkIcons && (
                (showBookmarkSuccess === itemId || isBookmarked || bookmarkId) ? (
                    <CiSquareCheck
                        className='bookmark_fun'
                        style={{ color: tempColor || (isCustomBookmark ? 'rgba(206, 206, 206, 0.84)' : 'rgb(255, 145, 0)') }}
                        onClick={isCustomBookmark ? handleCustomBookmarkClick : undefined}
                    />
                ) : (
                    <CiBookmarkMinus className='bookmark_fun' onClick={handleBookmarkPost} />

                )
            )}
            <PiNotePencilThin className='edit' onClick={handleEditClick} />


            {showCopySuccess === itemId ? (
                <CiSquareCheck className='copy_cheeck' />
            ) : (

                <PiCopySimpleThin className='copy' onClick={handleCopyClick} />

            )}
            <PiTrashThin className={`delete_fun ${selectedMessageId === itemId ? 'active' : ''}`} onClick={handleDeleteClick} />

        </div>
    );
};

export default OptionInPost;
